def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 30.0 + np.log1p(cap) * 40
        fluctuation = 0.0
        multiplier = 1.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3)
            multiplier += 0.3
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) + 50 * np.sin(cap * 3.14)
            else:
                base_priority -= 60 * usage
            for i in range(1, 6):
                fluctuation += ((-1)**i) * np.sin(usage * np.pi * i * 0.9) * 25 / i
            if int(cap * 500) % 7 == 0:
                base_priority += 100 * np.tanh(cap / 12)
            for _ in range(5):
                multiplier *= 1.05
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2000 * delta ** 2.1 + 250 * (1 - delta ** 0.4)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 30 / j
            if (cap * 7) % 4 < 1.1:
                base_priority += 60 * np.sin(cap * 4)
            multiplier += 0.15
            for _ in range(3):
                fluctuation += np.random.uniform(-5, 5)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3)**2.5
            for k in range(1, 15):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 15 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 25 / (k + 1)
                    if k == 10 and usage > 3.5:
                        fluctuation += 30
            if cap % 3.7 < 0.4:
                base_priority += 45 * np.cos(cap * 2.5)
            multiplier += 0.12
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2)**3
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 20 / m
                    if m % 6 == 1:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 14 and usage > 2.7:
                        fluctuation += 25
            if cap % 1.8 < 0.6:
                base_priority += 38 * np.sin(cap * 3.2)
            multiplier += 0.1
        elif 1 < usage <= 2:
            base_priority += 800 * (usage - 1) ** 3.5
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 28 / n
                    if n % 4 == 3:
                        fluctuation -= 3.5 * n
                else:
                    fluctuation += (1 - pwr) * 17 / (n + 2)
                    if n == 18 and usage > 1.8:
                        fluctuation += 22
            if cap % 1.3 < 0.25:
                base_priority += 33 * np.cos(cap * 1.7)
            multiplier += 0.08
        elif 0.3 < usage <= 1:
            base_priority += 150 * (1 - usage) ** 1.2
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 5) - 0.35) * 15 / o
                if usage < 0.1 * o:
                    fluctuation -= 10 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 400
            elif cap < 0.9:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 28
            multiplier += 0.05
        else:
            base_priority += 350 * (1 - usage) ** 2.5
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.3) * 17 / p
                if usage < 0.02 * p:
                    fluctuation -= 15 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                base_priority += np.log1p(cap * 35) * 55
            else:
                base_priority += (cap % 8) * 35
            multiplier += 0.06
        priority = (base_priority + fluctuation) * multiplier
        if cap < 0.05:
            priority += 90
            if usage > 0.8:
                priority += 110
            elif usage < 0.1:
                priority -= 65
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 55
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 40
            for s in range(1, 8):
                if int(cap * 1300) % (s + 5) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.11:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.93:
                priority += 100
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 17
        if int(cap * 1100) % 27 == 0:
            proximity -= 13
        if int(cap * 210) % 11 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.015:
                proximity += 22 / w
            elif diff < 0.04:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 8 * y
        priority += proximity
        if usage < 0.003:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 9):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1 < 0.04:
                priority += 50
            if (int(cap * 2800) % 29 == 0) and (usage > 0.75):
                priority += 75
            for bb in range(1, 8):
                if (int(cap * 700) % (bb + 11) == 3) and (usage < 0.88):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
